 62→const CanvasImageNode = ({
 63→    canvasImage,
 64→    stageWidth,
 65→    stageHeight,
 66→    isSelected,
 67→    isDragging,
 68→    onSelect,
 69→    onDragStart,
 70→    onDragEnd,
 71→    canInteract,
 72→    preventTouchDefault,
 73→    isBeingRemoved
 74→}) => {
 75→    const loadedImage = useLoadedImage(canvasImage?.src);
 76→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 77→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 78→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 79→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 80→    const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
 81→    const baseScaleX = canvasImage?.scaleX === -1 ? -1 : 1;
 82→
 83→    return (
 84→        <>
 85→            <KonvaImage
 86→                name={canvasImage?.id}
 87→                x={x}
 88→                y={y}
 89→                width={objectWidth}
 90→                height={objectHeight}
 91→                image={loadedImage}
 92→                draggable={canInteract && !isBeingRemoved}
 93→                rotation={canvasImage?.rotation || 0}
 94→                scaleX={baseScaleX * liftMultiplier}
 95→                scaleY={liftMultiplier}
 96→                shadowColor="rgba(0,0,0,0.3)"
 97→                shadowBlur={isSelected || isDragging ? 16 : 8}
 98→                shadowOffsetY={isSelected || isDragging ? 6 : 3}
 99→                preventDefault={preventTouchDefault}
100→                onClick={canInteract ? onSelect : undefined}

  1→import { useEffect, useMemo, useRef, useState } from 'react';
  2→import CanvasSurface, { buildSortedCanvasObjects, getCanvasStageHeight } from '../../Canvas/CanvasSurface';
  3→import { parseCanvasDoc } from '../../../../utils/canvasDoc';
  4→import './canvaspreview.css';
  5→
  6→const CANVAS_BASE_WIDTH = 560;
  7→const PREVIEW_MIN_WIDTH = 120;
  8→const PREVIEW_FALLBACK_WIDTH = 220;
  9→const PREVIEW_MIN_HEIGHT = 90;
 10→const PREVIEW_LAZY_ROOT_MARGIN = '320px 0px';
 11→
 12→const CanvasPreview = ({ canvasDoc }) => {
 13→    const containerRef = useRef(null);
 14→    const [containerSize, setContainerSize] = useState({
 15→        width: PREVIEW_FALLBACK_WIDTH,
 16→        height: PREVIEW_FALLBACK_WIDTH,
 17→    });
 18→    const [hasEnteredViewport, setHasEnteredViewport] = useState(false);
 19→    const parsed = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);
 20→    const { meta, snippets, images, doodles } = parsed;
 21→    const isEmpty = snippets.length === 0 && images.length === 0 && doodles.length === 0;
 22→    const isDark = meta.theme === 'dark';
 23→    const aspectClass = meta.aspectRatio === '4:5' ? 'is-4-5' : 'is-1-1';
 24→
 25→    useEffect(() => {
 26→        const updateWidth = () => {
 27→            const nextWidth = containerRef.current?.clientWidth || PREVIEW_FALLBACK_WIDTH;
 28→            const nextHeight = containerRef.current?.clientHeight || PREVIEW_FALLBACK_WIDTH;
 29→            setContainerSize((prev) => (
 30→                prev.width === nextWidth && prev.height === nextHeight
 31→                    ? prev
 32→                    : { width: nextWidth, height: nextHeight }
 33→            ));
 34→        };
 35→
 36→        updateWidth();
 37→        window.addEventListener('resize', updateWidth);
 38→
 39→        let resizeObserver = null;
 40→        if (typeof ResizeObserver !== 'undefined' && containerRef.current) {
 41→            resizeObserver = new ResizeObserver(updateWidth);
 42→            resizeObserver.observe(containerRef.current);
 43→        }
 44→
 45→        return () => {
 46→            window.removeEventListener('resize', updateWidth);
 47→            if (resizeObserver) {
 48→                resizeObserver.disconnect();
 49→            }
 50→        };
 51→    }, []);
 52→
 53→    useEffect(() => {
 54→        if (isEmpty || hasEnteredViewport) {
 55→            return;
 56→        }
 57→
 58→        const element = containerRef.current;
 59→        if (!element) {
 60→            return;
 61→        }
 62→
 63→        if (typeof IntersectionObserver !== 'function') {
 64→            setHasEnteredViewport(true);
 65→            return;
 66→        }
 67→
 68→        const observer = new IntersectionObserver(
 69→            (entries) => {
 70→                if (entries.some((entry) => entry.isIntersecting || entry.intersectionRatio > 0)) {
 71→                    setHasEnteredViewport(true);
 72→                    observer.disconnect();
 73→                }
 74→            },
 75→            {
 76→                root: null,
 77→                rootMargin: PREVIEW_LAZY_ROOT_MARGIN,
 78→                threshold: 0.01,
 79→            }
 80→        );
 81→
 82→        observer.observe(element);
 83→        return () => observer.disconnect();
 84→    }, [isEmpty, hasEnteredViewport]);
 85→
 86→    const sortedObjects = useMemo(() => buildSortedCanvasObjects(snippets, images), [snippets, images]);
 87→    const viewportWidth = Math.max(PREVIEW_MIN_WIDTH, containerSize.width);
 88→    const fallbackHeight = getCanvasStageHeight(viewportWidth, meta.aspectRatio);
 89→    const viewportHeight = Math.max(PREVIEW_MIN_HEIGHT, containerSize.height || fallbackHeight);
 90→    const stageWidth = CANVAS_BASE_WIDTH;
 91→    const stageHeight = getCanvasStageHeight(stageWidth, meta.aspectRatio);
 92→    const fitScale = Math.min(viewportWidth / stageWidth, viewportHeight / stageHeight);
 93→    const fitOffsetX = (viewportWidth - stageWidth * fitScale) / 2;
 94→    const fitOffsetY = (viewportHeight - stageHeight * fitScale) / 2;
 95→
 96→    return (
 97→        <div
 98→            ref={containerRef}
 99→            className={`canvas-preview ${isDark ? 'is-dark' : 'is-light'} ${aspectClass}`}
100→            aria-hidden="true"
101→        >
102→            <div className="canvas-preview-dots" />
103→
104→            {isEmpty ? (
105→                <span className="canvas-preview-empty">Canvas</span>
106→            ) : hasEnteredViewport ? (
107→                <CanvasSurface
108→                    viewportWidth={viewportWidth}
109→                    viewportHeight={viewportHeight}
110→                    stageWidth={stageWidth}
111→                    stageHeight={stageHeight}
112→                    fitScale={fitScale}
113→                    fitOffsetX={fitOffsetX}
114→                    fitOffsetY={fitOffsetY}
115→                    viewport={{ scale: 1, x: 0, y: 0 }}
116→                    gridEnabled={Boolean(meta.gridEnabled)}
117→                    theme={meta.theme}
118→                    doodles={doodles}
119→                    sortedObjects={sortedObjects}
120→                    className="canvas-preview-stage"
121→                />
122→            ) : (
123→                <span className="canvas-preview-loading">Loading canvas...</span>
124→            )}
125→        </div>
126→    );
127→};
128→
129→export default CanvasPreview;
